import { Action } from 'redux-saga';
import createReducer from '~/redux/store/createReducer';

export const AutomaticDebitTypes = {
  AUTOMATIC_DEBIT_CLEAN: '@dacc/AUTOMATIC_DEBIT_CLEAN',
  AUTOMATIC_DEBIT_FAILED: '@dacc/AUTOMATIC_DEBIT_FAILED',
  AUTOMATIC_DEBIT_REQUEST: '@dacc/AUTOMATIC_DEBIT_REQUEST',
  AUTOMATIC_DEBIT_SUCCESS: '@dacc/AUTOMATIC_DEBIT_SUCCESS',
} as const;

export interface AutomaticDebtResponse {
  isActive: boolean;
  code: number;
  message: string;
  data: {
    branchNumber: string;
    checkingAccountNumber: string;
    bankNumber: string;
  };
  errors: [];
}

export interface AutomaticDebtReducerProps {
  isError: boolean;
  isLoading: boolean;
  data: AutomaticDebtResponse | undefined;
}

type State = AutomaticDebtReducerProps;

const initialState: AutomaticDebtReducerProps = {
  isLoading: false,
  isError: false,
  data: undefined,
};

const automaticDebtReducer = createReducer(initialState, {
  [AutomaticDebitTypes.AUTOMATIC_DEBIT_REQUEST](state: State): State {
    return { ...state, isLoading: true };
  },
  [AutomaticDebitTypes.AUTOMATIC_DEBIT_SUCCESS](
    state: State,
    { data }: { data: AutomaticDebtResponse },
  ): State {
    return { ...state, isLoading: false, isError: false, data };
  },
  [AutomaticDebitTypes.AUTOMATIC_DEBIT_FAILED](state: State): State {
    return { ...state, isLoading: false, isError: true };
  },
  [AutomaticDebitTypes.AUTOMATIC_DEBIT_CLEAN](): State {
    return initialState;
  },
});

interface AutomaticDebtActions {
  automaticDebtRequest: () => Action;
  automaticDebtSuccess: (data: AutomaticDebtResponse) => Action;
  automaticDebtClean: () => Action;
  automaticDebtError: () => Action;
}

export const automaticDebtActions: AutomaticDebtActions = {
  automaticDebtRequest: () => ({
    type: AutomaticDebitTypes.AUTOMATIC_DEBIT_REQUEST,
  }),
  automaticDebtSuccess: (data: AutomaticDebtResponse) => ({
    type: AutomaticDebitTypes.AUTOMATIC_DEBIT_SUCCESS,
    data,
  }),
  automaticDebtError: () => ({
    type: AutomaticDebitTypes.AUTOMATIC_DEBIT_FAILED,
  }),
  automaticDebtClean: () => ({
    type: AutomaticDebitTypes.AUTOMATIC_DEBIT_CLEAN,
  }),
};

export default automaticDebtReducer;

