import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum DuplicateCardTypes {
  REQUEST = '@duplicateCard/REQUEST',
  SUCCESS = '@duplicateCard/SUCCESS',
  FAILED = '@duplicateCard/FAILED',
  CLEAR = '@duplicateCard/CLEAR',
}

export interface DuplicateCardResponse {
  code: number;
  message: string;
  data: object;
}

export interface DuplicateCardReducerProps {
  isLoading: boolean;
  isError: boolean;
  data: DuplicateCardResponse | undefined;
}

type State = DuplicateCardReducerProps;

const initialState: DuplicateCardReducerProps = {
  isLoading: false,
  isError: false,
  data: undefined,
};

const duplicateCardReducer = createReducer(initialState, {
  [DuplicateCardTypes.REQUEST](state: State) {
    return {
      ...state,
      isLoading: true,
    };
  },
  [DuplicateCardTypes.SUCCESS](
    state: State,
    {
      data,
    }: {
      data: DuplicateCardResponse;
    },
  ) {
    return {
      ...state,
      data,
      isLoading: false,
      isError: false,
    };
  },
  [DuplicateCardTypes.FAILED](
    state: State,
    {
      data,
    }: {
      data: DuplicateCardResponse;
    },
  ) {
    return {
      ...state,
      data,
      isLoading: false,
      isError: true,
    };
  },
  [DuplicateCardTypes.CLEAR](): State {
    return initialState;
  },
});

type DuplicateCardActions = {
  duplicateCardRequest: (data: {
    lastFourNumbers: string;
    accountNumber: string;
    isVirtual: boolean;
    reasonBlockCode?: string;
    organizationNumber: number;
    onSuccess?: () => void;
    onFailed?: () => void;
  }) => Action;
  duplicateCardSuccess: (data: { data: DuplicateCardResponse }) => Action;
  duplicateCardFailed: (data: { data: DuplicateCardResponse }) => Action;
  duplicateCardClear: () => Action;
};

export const duplicateCardActions: DuplicateCardActions = {
  duplicateCardRequest: (data: {
    lastFourNumbers: string;
    accountNumber: string;
    isVirtual: boolean;
    organizationNumber: number;
    onFailed?: () => void;
  }) => ({
    type: DuplicateCardTypes.REQUEST,
    data,
  }),
  duplicateCardSuccess: (data: { data: DuplicateCardResponse }) => ({
    type: DuplicateCardTypes.SUCCESS,
    data,
  }),
  duplicateCardFailed: (data: { data: DuplicateCardResponse }) => ({
    type: DuplicateCardTypes.FAILED,
    data,
  }),
  duplicateCardClear: () => ({
    type: DuplicateCardTypes.CLEAR,
  }),
};

export default duplicateCardReducer;

