import createReducer from '../store/createReducer';

/**
 * Types
 */
const Types = {
  FORGOT_SMS_REQUEST: 'FORGOT_SMS_REQUEST',
  RESPONSE_SMS: 'RESPONSE_SMS',
  CLEAR_LOADING: 'CLEAR_LOADING',

  GET_VALIDATE_PIN: 'GET_VALIDATE_PIN',
  RESPONSE_PIN: 'RESPONSE_PIN',
  FAILED_PIN: 'FAILED_PIN',

  GET_CHANGE_PASSWORD: 'GET_CHANGE_PASSWORD',
  SUCCESS_CHANGE_PASSWORD: 'SUCCESS_CHANGE_PASSWORD',
  FAILED_CHANGE_PASSWORD: 'FAILED_CHANGE_PASSWORD',

  SET_MODAL_CODE: 'SET_MODAL_CODE',
  SET_STEP: 'SET_STEP',
  SHOW_LOADING: 'SHOW_LOADING',
  CLEAR: 'CLEAR',
};

/**
 * Initial State
 */
interface InitialState {
  dados: any;
  isLoadingEmail: boolean;
  isLoadingSMS: boolean;
  isLoading: boolean;
  success: boolean;
  errorPin: boolean;
  step: number;
  modalCode: number;
}

type State = InitialState;

export const initialState: InitialState = {
  dados: [],
  isLoadingEmail: false,
  isLoadingSMS: false,
  isLoading: false,
  success: false,
  errorPin: false,
  modalCode: 0,
  step: 1,
};

/**
 * Reducers
 */
const forgotReducer = createReducer(initialState, {
  [Types.FORGOT_SMS_REQUEST](
    state: InitialState,
    {isPhone}: {isPhone: boolean},
  ) {
    return {
      ...state,
      isLoadingSMS: !!isPhone,
      isLoadingEmail: !isPhone,
    };
  },
  [Types.CLEAR_LOADING](state: InitialState) {
    return {
      ...state,
      isLoadingSMS: false,
      isLoadingEmail: false,
      isLoading: false,
    };
  },
  [Types.SHOW_LOADING](state: InitialState) {
    return {
      ...state,
      isLoadingSMS: false,
      isLoadingEmail: false,
      isLoading: true,
    };
  },
  [Types.RESPONSE_SMS](state: InitialState) {
    return {
      ...state,
      isLoadingSMS: false,
      isLoadingEmail: false,
    };
  },
  [Types.GET_VALIDATE_PIN](state: InitialState) {
    return {
      ...state,
      errorPin: false,
      isLoading: true,
    };
  },
  [Types.RESPONSE_PIN](state: InitialState) {
    return {
      ...state,
      errorPin: false,
      isLoading: false,
    };
  },
  [Types.GET_CHANGE_PASSWORD](state: InitialState) {
    return {
      ...state,
      isLoading: true,
    };
  },
  [Types.FAILED_PIN](state: InitialState) {
    return {
      ...state,
      errorPin: true,
      isLoading: false,
    };
  },
  [Types.SET_STEP](state: InitialState, {step}: {step: number}) {
    return {
      ...state,
      step,
    };
  },
  [Types.CLEAR](state: InitialState) {
    return {
      ...state,
      dados: [],
      isLoadingEmail: false,
      isLoadingSMS: false,
      isLoading: false,
      success: false,
      errorPin: false,
      modalCode: 0,
      step: 1,
    };
  },
  [Types.SET_MODAL_CODE](
    state: InitialState,
    {modalCode}: {modalCode: number},
  ) {
    return {
      ...state,
      modalCode,
    };
  },
});

/**
 * Actions
 */
export const Creators = {
  requestForgotSMS: (data: {
    document: string;
    isPhone: boolean;
    isAgain?: boolean;
    activateDevice?: number;
  }) => ({
    type: Types.FORGOT_SMS_REQUEST,
    document: data.document,
    isPhone: data.isPhone,
    isAgain: data.isAgain,
    activateDevice: data.activateDevice,
  }),
  responseForgotSMS: (phone?: boolean) => ({
    type: Types.RESPONSE_SMS,
    phone,
  }),
  clearLoading: () => ({
    type: Types.CLEAR_LOADING,
  }),
  showLoading: () => ({
    type: Types.SHOW_LOADING,
  }),
  getValidatePin: (data: {
    document: string;
    pin: string;
    activateDevice?: number;
  }) => ({
    type: Types.GET_VALIDATE_PIN,
    document: data.document,
    pin: data.pin,
    activateDevice: data.activateDevice,
  }),
  responseValidatePin: () => ({
    type: Types.RESPONSE_PIN,
  }),
  failedPin: () => ({
    type: Types.FAILED_PIN,
  }),
  getChangePassword: (cpf: string, pin: string, senhaNova: string) => ({
    type: Types.GET_CHANGE_PASSWORD,
    cpf,
    pin,
    senhaNova,
  }),
  setStep: (step: number) => ({
    type: Types.SET_STEP,
    step,
  }),
  clearForgotPasswordReducer: () => ({
    type: Types.CLEAR,
  }),
  setModalCode: (modalCode: number) => ({
    type: Types.SET_MODAL_CODE,
    modalCode,
  }),
};

export default forgotReducer;

