import moment from 'moment';
import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum LivenessTypes {
  REQUEST = '@Liveness/LIVENESS_REQUEST',
  SUCCESS = '@Liveness/LIVENESS_SUCCESS',
  FAILED = '@Liveness/LIVENESS_FAILED',
  CLEAR_ERROR = '@Liveness/LIVENESS_CLEAR_ERROR',
  CLEAR = '@Liveness/LIVENESS_CLEAR',
}

export interface LivenessResponse {
  data: {
    success: boolean;
    cpf: string;
    status: number;
  }
}

export type LivenessCallback = (data: {
  statusCode: number | undefined;
  success: boolean | undefined;
  response?: LivenessResponse;
}) => void;

export interface LivenessReducerProps {
  isLoading: boolean;
  isError: boolean;
  blockedUntil: Date | undefined;
  attempts: number;
}

type State = LivenessReducerProps;

export const initialState: LivenessReducerProps = {
  isLoading: false,
  isError: false,
  blockedUntil: undefined,
  attempts: 0,
};

const livenessReducer = createReducer(initialState, {
  [LivenessTypes.REQUEST](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [LivenessTypes.SUCCESS](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: false,
      attempts: 0,
    };
  },
  [LivenessTypes.FAILED](state: State): State {
    const attempts = state.attempts + 1;
    const isBlocked = attempts >= 7;

    return {
      ...state,
      isLoading: false,
      isError: true,
      attempts,
      blockedUntil: isBlocked
        ? new Date(moment().add(1, 'd').format())
        : state.blockedUntil,
    };
  },
  [LivenessTypes.CLEAR_ERROR](state: State): State {
    return {
      ...state,
      isError: false,
    };
  },
  [LivenessTypes.CLEAR](): State {
    return initialState;
  },
});

type LivenessActions = {
  livenessRequest: (preview: string, callback: LivenessCallback) => Action;
  livenessSuccess: () => Action;
  livenessFailed: () => Action;
  livenessClearError: () => Action;
  livenessClear: () => Action;
};

export const livenessActions: LivenessActions = {
  livenessRequest: (preview, callback) => ({
    type: LivenessTypes.REQUEST,
    preview,
    callback,
  }),
  livenessSuccess: () => ({
    type: LivenessTypes.SUCCESS,
  }),
  livenessFailed: () => ({
    type: LivenessTypes.FAILED,
  }),
  livenessClearError: () => ({
    type: LivenessTypes.CLEAR_ERROR,
  }),
  livenessClear: () => ({
    type: LivenessTypes.CLEAR,
  }),
};

export default livenessReducer;

