import createReducer from '~/redux/store/createReducer';

/**
 * Types
 */
export const Types = {
  REFUEL_STATUS_REQUEST: 'REFUEL_STATUS_REQUEST',
  REFUEL_STATUS_SUCCESS: 'REFUEL_STATUS_SUCCESS',
  REFUEL_STATUS_FAILED: 'REFUEL_STATUS_FAILED',
  CHANGE_VISIBLE_ONBOARD: 'CHANGE_VISIBLE_ONBOARD',
  REFUEL_CLEAR_DATA: 'REFUEL_CLEAR_DATA',
  REFUEL_REQUEST_REQUEST: 'REFUEL_REQUEST_REQUEST',
  REFUEL_REQUEST_SUCESS: 'REFUEL_REQUEST_SUCESS',
  REFUEL_REQUEST_FAILED: 'REFUEL_REQUEST_FAILED',
  REFUEL_REQUEST_CLEAR: 'REFUEL_REQUEST_CLEAR',
  REFUEL_REQUEST_TERM_CHECKED: 'REFUEL_REQUEST_TERM_CHECKED',
  REFUEL_REQUEST: 'REFUEL_REQUEST',
  REFUEL_SUCCESS: 'REFUEL_SUCCESS',
  REFUEL_FAILED: 'REFUEL_FAILED',
  REFUEL_VERIFY_PHONE: 'REFUEL_VERIFY_PHONE',
  REFUEL_VERIFY_CREDITCARD: 'REFUEL_VERIFY_CREDITCARD',
  REFUEL_HAS_CREDITCARD: 'REFUEL_HAS_CREDITCARD',
  REFUEL_DATA_CREDITCARD: 'REFUEL_DATA_CREDITCARD',
  REFUEL_CHANGEPHONE: 'REFUEL_CHANGEPHONE',
  REFUEL_CHANGEPHONE_LOADING: 'REFUEL_CHANGEPHONE_LOADING',
  REFUEL_CHANGE_CREDITCARD: 'REFUEL_CHANGE_CREDITCARD',
  REFUEL_SELECTED_VEHICLE_STATUS_FAILED: 'REFUEL_SELECTED_VEHICLE_STATUS_FAILED',
  REFUEL_ENABLE_SERVICE: 'REFUEL_ENABLE_SERVICE',
  REFUEL_DISABLE_SERVICE: 'REFUEL_DISABLE_SERVICE',
  REFUEL_INSERT_ACCOUNT_REQUEST: 'REFUEL_INSERT_ACCOUNT_REQUEST',
  REFUEL_INSERT_ACCOUNT_SUCCESS: 'REFUEL_INSERT_ACCOUNT_SUCCESS',
  REFUEL_INSERT_ACCOUNT_FAILED: 'REFUEL_INSERT_ACCOUNT_FAILED',
  REFUEL_INSERT_ACCOUNT_LOADING: 'REFUEL_INSERT_ACCOUNT_LOADING',

  REFUEL_CHANGE_PAYMENT_METHOD: 'REFUEL_CHANGE_PAYMENT_METHOD',
  REFUEL_CHANGE_PAYMENT_METHOD_SUCCESS: 'REFUEL_CHANGE_PAYMENT_METHOD_SUCCESS',
  REFUEL_CHANGE_PAYMENT_METHOD_FAILED: 'REFUEL_CHANGE_PAYMENT_METHOD_FAILED',

  REFUEL_TRIGGER_INFOALERT: 'REFUEL_CHANGE_INFOALERT'
};

/**
 * Initial State
 */

interface RefuelDataType {
  celular: string;
  isAbasteceAtivo: boolean;
  produto: {
    codigoProduto: string;
    nomeProduto: string;
    valorLimiteUsoTotal: string;
  };
}

interface InfoAlertProps {
  title: string;
  description: string;
  textNext: string;
  onNextPress: () => void | any;
  textClose?: string;
  onClosePress?: () => void | any;
}

interface InfoAlert extends InfoAlertProps {
  visible: boolean
}

interface propsState {
  data: string | RefuelDataType;
  isLoading: boolean;
  isFailVehicleStatus: boolean;
  hasCreditCard: boolean;
  needCredCard: boolean;
  dataCredCard: string | any;
  changedPhone: string;
  isVisibleOnboard: boolean;
  isSuccessChangePaymentMethod: boolean;
  isLoadingChangePaymentMethod: boolean;
  isErrorChangePaymentMethod: boolean;
  showModalAlertChangePayment?: boolean;
  infoAlert: InfoAlert
}

export type State = propsState;

const emptyInfoAlert: InfoAlert = {
  visible: false,
  title: '',
  description: '',
  textNext: '',
  onNextPress: () => null,
  textClose: '',
  onClosePress: () => null
}

export const initialState: propsState = {
  data: '',
  isLoading: false,
  isFailVehicleStatus: false,
  hasCreditCard: false,
  needCredCard: false,
  dataCredCard: '',
  changedPhone: '',
  isVisibleOnboard: false,
  isSuccessChangePaymentMethod: false,
  isLoadingChangePaymentMethod: false,
  isErrorChangePaymentMethod: false,
  showModalAlertChangePayment: false,
  infoAlert: emptyInfoAlert
};

export const refuelReducer = createReducer(initialState, {
  [Types.REFUEL_STATUS_REQUEST](state: propsState) {
    return {
      ...state,
      isLoading: true,
      isFailVehicleStatus: false,
    };
  },
  [Types.REFUEL_HAS_CREDITCARD](state: propsState, { data }: { data: boolean }) {
    return {
      ...state,
      hasCreditCard: data,
    };
  },
  [Types.REFUEL_DATA_CREDITCARD](state: propsState, { data }: { data: any }) {
    return {
      ...state,
      dataCredCard: data,
    };
  },
  [Types.REFUEL_STATUS_SUCCESS](
    state: propsState,
    {
      data,
    }: {
      data: {
        isAbasteceAtivo: boolean;
        produto: {
          codigoProduto: string;
          nomeProduto: string;
          valorLimiteUsoTotal: string;
        };
        celular: string;
      };
    }
  ) {
    return {
      ...state,
      isLoading: false,
      isFailVehicleStatus: false,
      data: data,
      needCredCard: false,
    };
  },
  [Types.REFUEL_STATUS_FAILED](state: propsState, { data }: { data: RefuelDataType }) {
    return {
      ...state,
      isLoading: false,
      isFailVehicleStatus: true,
      data: data,
      needCredCard: true,
    };
  },
  [Types.CHANGE_VISIBLE_ONBOARD](
    state: propsState,
    {
      data: { isVisible, needCredCard },
    }: {
      data: {
        isVisible: boolean;
        needCredCard: boolean;
      };
    }
  ) {
    return {
      ...state,
      isLoading: false,
      needCredCard: needCredCard,
      isVisibleOnboard: isVisible,
    };
  },
  [Types.REFUEL_REQUEST](state: propsState) {
    return {
      ...state,
      isLoading: true,
      isFailVehicleStatus: false,
    };
  },
  [Types.REFUEL_SUCCESS](state: propsState) {
    return {
      ...state,
      isLoading: false,
      isFailVehicleStatus: false,
    };
  },
  [Types.REFUEL_FAILED](state: propsState) {
    return {
      ...state,
      isLoading: false,
    };
  },

  [Types.REFUEL_SELECTED_VEHICLE_STATUS_FAILED](state: propsState) {
    return {
      ...state,
      isLoading: false,
      isFailVehicleStatus: true,
    };
  },

  [Types.REFUEL_CHANGEPHONE_LOADING](state: propsState, { data }: { data: boolean }) {
    return {
      ...state,
      isLoading: data,
    };
  },

  [Types.REFUEL_CHANGEPHONE](state: propsState, { data }: { data: string }) {
    return {
      ...state,
      changedPhone: data,
    };
  },

  [Types.REFUEL_CLEAR_DATA](state: propsState) {
    return initialState;
  },

  [Types.REFUEL_CHANGE_PAYMENT_METHOD](state: propsState) {
    return {
      ...state,
      isLoadingChangePaymentMethod: true,
      isErrorChangePaymentMethod: false,
    };
  },

  [Types.REFUEL_CHANGE_PAYMENT_METHOD_SUCCESS](state: propsState, { showModalAlertChangePayment = true }: { showModalAlertChangePayment: State['showModalAlertChangePayment'] }) {
    return {
      ...state,
      isLoadingChangePaymentMethod: false,
      isSuccessChangePaymentMethod: true,
      showModalAlertChangePayment
    };
  },

  [Types.REFUEL_CHANGE_PAYMENT_METHOD_FAILED](state: propsState) {
    return {
      ...state,
      isLoadingChangePaymentMethod: false,
      isErrorChangePaymentMethod: true,
    };
  },

  [Types.REFUEL_TRIGGER_INFOALERT](state: propsState, { data: infoAlertData }: { data: InfoAlertProps }) {
    return {
      ...state,
      infoAlert: infoAlertData
    }
  }
});

/**
 * Actions
 */
export const Creators = {
  refuelStatusRequest: (data: {
    codigoCliente: string;
    placa: string;
