    data,
  }),

  hasCreditCard: (data: boolean) => ({
    type: Types.REFUEL_HAS_CREDITCARD,
    data,
  }),

  dataCreditCard: (data: any) => ({
    type: Types.REFUEL_DATA_CREDITCARD,
    data,
  }),

  refuelChangePhoneLoading: (data: boolean) => ({
    type: Types.REFUEL_CHANGEPHONE_LOADING,
    data,
  }),

  refuelSelectedVehicleStatusFailed: () => ({
    type: Types.REFUEL_SELECTED_VEHICLE_STATUS_FAILED,
  }),

  refuelChangePhone: (data: string) => ({
    type: Types.REFUEL_CHANGEPHONE,
    data,
  }),

  changeCreditCard: (data: {
    nome: string;
    cartao: string;
    validade: string;
    flag: string;
    identifier: string;
  }) => ({
    type: Types.REFUEL_CHANGE_CREDITCARD,
    data,
  }),

  disableService: (data: {
    celular: string;
    codigoCliente: string;
    codigoProduto: string;
    placa: string;
    numeroIdentificador: string;
  }) => ({
    type: Types.REFUEL_DISABLE_SERVICE,
    data,
  }),

  refuelInsertAccountRequest: (data: {
    codigoCliente: string;
    numeroCelular: string;
    numeroIdentificador: string;
    dadosPagamento: {
      numeroCartao: string;
      codigoSeguranca: string;
      codigoBandeiraCartao: string;
      mesValidade: string;
      anoValidade: string;
      nomeClienteCartao: string;
    };
    placa?: string;
  }) => ({
    type: Types.REFUEL_INSERT_ACCOUNT_REQUEST,
    data,
  }),

  refuelInsertAccountFailed: () => ({
    type: Types.REFUEL_INSERT_ACCOUNT_FAILED,
  }),

  refuelInsertAccountLoading: (data: boolean) => ({
    type: Types.REFUEL_INSERT_ACCOUNT_LOADING,
    data,
  }),

  refuelClearData: () => ({
    type: Types.REFUEL_CLEAR_DATA,
  }),

  changePaymentMethodRefuel: (data: {
    disableActualPaymentRefuel: any;
    newPaymentRefuel: any;
  }) => ({
    type: Types.REFUEL_CHANGE_PAYMENT_METHOD,
    ...data
  }),

  changePaymentMethodRefuelSuccess: (showModalAlertChangePayment?: boolean) => ({
    type: Types.REFUEL_CHANGE_PAYMENT_METHOD_SUCCESS,
    showModalAlertChangePayment
  }),

  errorChangePaymentMethodRefuel: () => ({
    type: Types.REFUEL_CHANGE_PAYMENT_METHOD_FAILED,
  }),

  showInfoAlert: (data: InfoAlertProps) => ({
    type: Types.REFUEL_TRIGGER_INFOALERT,
    data: { ...data, visible: true }
  }),

  dismissInfoAlert: () => ({
    type: Types.REFUEL_TRIGGER_INFOALERT,
    data: { ...emptyInfoAlert, visible: false }
  })
};

export default refuelReducer;

