import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum SearchCepTypes {
  REQUEST = '@searchCep/SEARCH_CEP_REQUEST',
  SUCCESS = '@searchCep/SEARCH_CEP_SUCCESS',
  FAILED = '@searchCep/SEARCH_CEP_FAILED',
  CLEAN = '@searchCep/SEARCH_CEP_CLEAN',
  CLEAN_LOADING = '@searchCep/SEARCH_CEP_CLEAN_LOADING',
}

export type SearchCepCallback = (data: {
  response: CepData | undefined;
  statusCode: number | undefined;
}) => void;

export interface CepData {
  Bairro: string;
  CEP: string;
  Cidade: string;
  Endereco: string;
  Estado: string;
  Complemento?: string;
}

export interface CepDataResponse {
  message: string;
  dadosEndereco: {
    endereco: string;
    codigoBairro: string;
    bairro: string;
    codigoCidade: number;
    cidade: string;
    codigoEstado: string;
    estado: string;
    codigoLocalidade: number;
    descricaoLocalidade: string;
  };
}

export interface SearchCepReducerProps {
  isLoading: boolean;
  error: string | undefined;
  statusCode: number | undefined;
  data: CepData;
}

type State = SearchCepReducerProps;

const initialState: SearchCepReducerProps = {
  isLoading: false,
  error: undefined,
  statusCode: undefined,
  data: {
    Bairro: '',
    CEP: '',
    Cidade: '',
    Endereco: '',
    Estado: '',
    Complemento: '',
  },
};

const searchCepReducer = createReducer(initialState, {
  [SearchCepTypes.REQUEST](state: State) {
    return {
      ...state,
      isLoading: true,
    };
  },
  [SearchCepTypes.SUCCESS](
    state: State,
    {
      data: { cepData, statusCode },
    }: {
      data: {
        cepData: CepData;
        statusCode: number | undefined;
      };
    },
  ) {
    return {
      ...state,
      data: cepData,
      statusCode,
      isLoading: false,
      error: '',
    };
  },
  [SearchCepTypes.FAILED](
    state: State,
    {
      data: { error, statusCode, cep },
    }: {
      data: {
        error: string | undefined;
        statusCode: number | undefined;
        cep: string;
      };
    },
  ) {
    return {
      data: {
        ...state.data,
        CEP: cep,
      },
      isLoading: false,
      error,
      statusCode,
    };
  },
  [SearchCepTypes.CLEAN](): State {
    return initialState;
  },
  [SearchCepTypes.CLEAN_LOADING](state: State): State {
    return {
      ...state,
      isLoading: false,
    };
  },
});

type SearchCepActions = {
  searchCepRequest: (cep: string, callback: SearchCepCallback) => Action;
  searchCepSuccess: (data: {
    cepData: CepData;
    statusCode: number | undefined;
  }) => Action;
  searchCepFailed: (data: {
    error: string | undefined;
    statusCode: number | undefined;
    cep: string;
  }) => Action;
  searchCepClean: () => Action;
  searchCepCleanLoading: () => Action;
};

export const searchCepActions: SearchCepActions = {
  searchCepRequest: (cep: string, callback: SearchCepCallback) => ({
    type: SearchCepTypes.REQUEST,
    cep,
    callback,
  }),
  searchCepSuccess: (data: {
    cepData: CepData;
    statusCode: number | undefined;
  }) => ({
    type: SearchCepTypes.SUCCESS,
    data,
  }),
  searchCepFailed: (data: {
    error: string | undefined;
    statusCode: number | undefined;
    cep: string;
  }) => ({
    type: SearchCepTypes.FAILED,
    data,
  }),
  searchCepClean: () => ({
    type: SearchCepTypes.CLEAN,
  }),
  searchCepCleanLoading: () => ({
    type: SearchCepTypes.CLEAN_LOADING,
  }),
};

type SearchCepReducerTypes = typeof searchCepActions;

export default searchCepReducer;

